/**
 * Track a tool execution (wrapper for convenience)
 */
export function trackTool(
  toolName: string,
  skillName: string | undefined,
  params: unknown,
  fn: () => Promise<unknown>,
): Promise<unknown> {
  const analytics = toolAnalytics;
  if (!analytics) {
    return fn();
  }

  const start = Date.now();

  return fn()
    .then((result) => {
      analytics.track({
        tool: toolName,
        skill: skillName,
        success: true,
        durationMs: Date.now() - start,
        paramsHash: analytics.hashParams(params),
        timestamp: Date.now(),
      });
      return result;
    })
    .catch((error) => {
      analytics.track({
        tool: toolName,
        skill: skillName,
        success: false,
        durationMs: Date.now() - start,
        error: error?.message || String(error),
        paramsHash: analytics.hashParams(params),
        timestamp: Date.now(),
      });
      throw error;
    });
}

