// Store pending actions
export const pendingPredictionActions = new Map<string, {
  predictionId: string;
  action: string;
  data: unknown;
  expiresAt: number;
}>();

// On user "yes" or action keyword
export async function executePredictionAction(userInput: string): Promise<boolean> {
  const pending = Array.from(pendingPredictionActions.values())
    .find(p => p.expiresAt > Date.now());

  if (!pending) return false;

  if (userInput === "yes" || userInput.includes(pending.action)) {
    await executeAction(pending.action, pending.data);
    pendingPredictionActions.delete(pending.predictionId);
    return true;
  }
}
