// Nightly job to adjust rule confidence
async function adjustRuleConfidence(): Promise<void> {
  const history = getPredictionHistory(30); // Last 30 days

  for (const rule of rules.values()) {
    const ruleHistory = history.filter(h => h.action === rule.id);
    const acceptanceRate = ruleHistory.filter(h => h.accepted).length / ruleHistory.length;

    // Adjust confidence based on acceptance
    if (acceptanceRate > 0.8) {
      rule.confidence = Math.min(1.0, rule.confidence + 0.05);
    } else if (acceptanceRate < 0.3) {
      rule.confidence = Math.max(0.5, rule.confidence - 0.1);
      if (rule.confidence < 0.6) {
        rule.enabled = false; // Auto-disable bad rules
      }
    }
  }
}
