Based on my deep analysis of the codebase and research, here's a comprehensive plan to make the predictive engine **automatic** and **well-wired** with all existing systems:

---

# 🔗 OpenClaw Predictive Engine: Full Integration Plan

## Architecture Overview

```
┌─────────────────────────────────────────────────────────────────┐
│                     PREDICTIVE ENGINE v2                         │
├─────────────────────────────────────────────────────────────────┤
│                                                                   │
│  ┌──────────────┐    ┌──────────────┐    ┌──────────────┐       │
│  │  EVENT MESH  │───▶│  PREDICTIONS │───▶│  DELIVERY    │       │
│  │  (Bus)       │    │  (Engine)    │    │  (Channels)  │       │
│  └──────────────┘    └──────────────┘    └──────────────┘       │
│         │                    │                    │               │
│         ▼                    ▼                    ▼               │
│  ┌──────────────┐    ┌──────────────┐    ┌──────────────┐       │
│  │ NEURO-MEMORY │    │  PATTERN     │    │  CRON JOBS   │       │
│  │ (Episodic)   │    │  LEARNING    │    │  (Schedule)  │       │
│  └──────────────┘    └──────────────┘    └──────────────┘       │
│         │                    │                    │               │
│         └────────────────────┴────────────────────┘               │
│                              │                                    │
│                              ▼                                    │
│                     ┌──────────────┐                             │
│                     │     MCP      │                             │
│                     │  (External)  │                             │
│                     └──────────────┘                             │
└─────────────────────────────────────────────────────────────────┘
```

---

## Phase 1: Auto-Wire Predictive Engine (Week 1)

### 1.1 Predictive Engine as Service

**Create `/src/agents/predictive-service.ts`:**

```typescript
/**
 * Predictive Service - Auto-started with Gateway
 * 
 * Integrates:
 * - Event Mesh (real-time events)
 * - Neuro-Memory (episodic memory)
 * - Cron System (scheduled checks)
 * - MCP (external triggers)
 */

import { PredictiveEngine, type PredictedAction } from "./predictive-engine.js";
import { getEventMesh, AgentEventMesh, EventTypes } from "./event-mesh.js";
import { 
  initPredictiveIntegration, 
  checkPredictions, 
  updatePredictiveContext,
  getPredictionStats 
} from "./predictive-integration.js";
import type { DatabaseSync } from "node:sqlite";
import { createSubsystemLogger } from "../logging/subsystem.js";

const log = createSubsystemLogger("predictive-service");

export type PredictiveServiceConfig = {
  enabled: boolean;
  agentId: string;
  db: DatabaseSync | null;
  neuroMemory?: {
    enabled: boolean;
    agentPath?: string;
  };
  autoDeliver: {
    enabled: boolean;
    maxPerDay: number;
    channels: string[];
    quietHours: { start: number; end: number };
  };
  schedule: {
    checkIntervalMs: number;  // How often to check predictions
    patternLearningEnabled: boolean;
    consolidationIntervalMs: number;
  };
};

export class PredictiveService {
  private engine: PredictiveEngine | null = null;
  private mesh: AgentEventMesh | null = null;
  private config: PredictiveServiceConfig;
  private checkInterval?: ReturnType<typeof setInterval>;
  private todayDeliveries = 0;
  private lastDeliveryTime = 0;

  constructor(config: PredictiveServiceConfig) {
    this.config = config;
  }

  /**
   * Start predictive service
   */
  async start(): Promise<void> {
    if (!this.config.enabled) {
      log.info("Predictive service disabled");
      return;
    }

    log.info("Starting predictive service...");

    // Initialize predictive integration
    const integration = initPredictiveIntegration({
      agentId: this.config.agentId,
      db: this.config.db,
      enabled: true,
      neuroMemory: this.config.neuroMemory,
    });

    this.engine = integration.engine;
    this.mesh = integration.mesh;

    // Wire to event mesh
    if (this.mesh) {
      this.wireToEventMesh();
    }

    // Start periodic checks
    this.startPeriodicChecks();

    // Subscribe to user actions for learning
    this.subscribeToUserActions();

    log.info("✅ Predictive service started");
  }

  /**
   * Wire predictive engine to event mesh
   */
  private wireToEventMesh(): void {
    if (!this.mesh) return;

    // Listen for relevant events
    const relevantEvents = [
      EventTypes.USER_MESSAGE,
      EventTypes.USER_COMMAND,
      "tool.execute",
      "calendar.event",
      "email.received",
      "task.due",
    ];

    for (const eventType of relevantEvents) {
      this.mesh.subscribe(eventType, async (event) => {
        // Update context with new event
        updatePredictiveContext({
          recentActivity: [{
            type: event.type,
            timestamp: event.timestamp,
            data: event.data,
          }],
        });

        // Learn pattern from user action
        if (this.config.schedule.patternLearningEnabled) {
          this.learnPatternFromEvent(event);
        }
      });
    }

    log.info(`Wired predictive engine to ${relevantEvents.length} event types`);
  }

  /**
   * Start periodic prediction checks
   */
  private startPeriodicChecks(): void {
    const intervalMs = this.config.schedule.checkIntervalMs || 30 * 60 * 1000; // 30 min default

    this.checkInterval = setInterval(async () => {
      await this.runPredictionCheck();
    }, intervalMs);

    log.info(`Periodic checks scheduled every ${intervalMs / 60000} minutes`);
  }

  /**
   * Run prediction check
   */
  private async runPredictionCheck(): Promise<void> {
    if (!this.engine) return;

    try {
      const predictions = await checkPredictions();

      if (predictions.length > 0 && this.shouldDeliver()) {
        await this.deliverTopPrediction(predictions[0]);
      }

      log.debug(`Prediction check: ${predictions.length} predictions`);
    } catch (error) {
      log.error("Prediction check failed:", error);
    }
  }

  /**
   * Check if we should deliver a prediction
   */
  private shouldDeliver(): boolean {
    if (!this.config.autoDeliver.enabled) return false;

    const now = new Date();
    const hour = now.getHours();

    // Check quiet hours
    const { start, end } = this.config.autoDeliver.quietHours;
    if (hour >= start || hour < end) return false;

    // Check daily limit
    if (this.todayDeliveries >= this.config.autoDeliver.maxPerDay) return false;

    // Check cooldown (at least 30 min between deliveries)
    const cooldownMs = 30 * 60 * 1000;
    if (Date.now() - this.lastDeliveryTime < cooldownMs) return false;

    // Reset counter at midnight
    const lastMidnight = new Date(now).setHours(0, 0, 0, 0);
    if (this.lastDeliveryTime < lastMidnight) {
      this.todayDeliveries = 0;
    }

    return true;
  }

  /**
   * Deliver top prediction via message
   */
  private async deliverTopPrediction(prediction: PredictedAction): Promise<void> {
    // This will be called via cron or event, not directly
    // to avoid circular dependencies with message tool
    log.info(`📊 Delivering prediction: ${prediction.action}`);

    // Emit event for delivery system to handle
    this.mesh?.emit({
      type: "prediction.deliver",
      source: "predictive-service",
      data: prediction,
    });

    this.todayDeliveries++;
    this.lastDeliveryTime = Date.now();
  }

  /**
   * Learn pattern from user event
   */
  private learnPatternFromEvent(event: any): void {
    if (!this.engine) return;

    const timeOfDay = this.getTimeOfDay(new Date(event.timestamp));
    const dayOfWeek = new Date(event.timestamp).toLocaleDateString("en", { weekday: "long" });

    this.engine.learnPattern({
      pattern: `${event.type}_${timeOfDay}_${dayOfWeek}`,
      category: this.categorizeEvent(event.type),
      frequency: 1,
      lastOccurrence: event.timestamp,
      confidence: 0.5,
      metadata: {
        eventType: event.type,
        timeOfDay,
        dayOfWeek,
      },
    });
  }

  /**
   * Subscribe to user actions
   */
  private subscribeToUserActions(): void {
    // Subscribe to tool executions
    this.mesh?.subscribe("tool.execute", async (event) => {
      const toolName = (event.data as any)?.tool;

      // Track specific tools
      const trackableTools = [
        "github", "email", "calendar", "task", "weather", "news",
        "imsg", "signal", "telegram", "slack", "discord"
      ];

      if (trackableTools.some(t => toolName?.includes(t))) {
        this.learnPatternFromEvent({
          type: `tool_${toolName}`,
          timestamp: event.timestamp,
          data: event.data,
        });
      }
    });
  }

  /**
   * Get time of day category
   */
  private getTimeOfDay(date: Date): string {
    const hour = date.getHours();
    if (hour >= 6 && hour < 12) return "morning";
    if (hour >= 12 && hour < 17) return "afternoon";
    if (hour >= 17 && hour < 21) return "evening";
    return "night";
  }

  /**
   * Categorize event type
   */
  private categorizeEvent(type: string): string {
    if (type.includes("calendar")) return "calendar";
    if (type.includes("email")) return "email";
    if (type.includes("task")) return "task";
    if (type.includes("github")) return "workflow";
    if (type.includes("imsg") || type.includes("signal") || type.includes("telegram")) {
      return "communication";
    }
    return "context";
  }

  /**
   * Get service status
   */
  getStatus() {
    const stats = getPredictionStats();
    return {
      enabled: this.config.enabled,
      running: this.engine !== null,
      todayDeliveries: this.todayDeliveries,
      stats,
      meshWired: this.mesh !== null,
    };
  }

  /**
   * Stop predictive service
   */
  async stop(): Promise<void> {
    if (this.checkInterval) {
      clearInterval(this.checkInterval);
    }

    this.engine?.close();
    this.engine = null;

    log.info("Predictive service stopped");
  }
}

// Singleton
