/**
 * MCP Tool for External Prediction Triggers
 * 
 * Allows external systems (like iOS Shortcuts, IFTTT, Zapier) to:
 * - Trigger prediction checks
 * - Query prediction status
 * - Record feedback
 */

import { Type } from "@sinclair/typebox";
import { type AnyAgentTool, jsonResult } from "./common.js";
import { checkPredictions, getPredictionStats } from "../predictive-integration.js";

const McpPredictiveSchema = Type.Object({
  action: Type.Union([
    Type.Literal("check"),
    Type.Literal("stats"),
    Type.Literal("trigger"),
  ]),
  category: Type.Optional(Type.String()),
  context: Type.Optional(Type.String()),
});

export function createMcpPredictiveTool(): AnyAgentTool {
  return {
    name: "mcp_predictive",
    label: "MCP Predictive",
    description: "External trigger for predictive engine (MCP integration)",
    parameters: McpPredictiveSchema,
    async execute(_toolCallId: string, params: Record<string, unknown>) {
      const action = params.action as string;

      switch (action) {
        case "check": {
          const predictions = await checkPredictions();
          return jsonResult({
            success: true,
            predictions,
            count: predictions.length,
          });
        }

        case "stats": {
          const stats = getPredictionStats();
          return jsonResult({
            success: true,
            stats,
          });
        }

        case "trigger": {
          // External trigger (e.g., iOS location change, time trigger)
          const category = params.category as string | undefined;
          const context = params.context as string | undefined;

          // Update context
          if (category || context) {
            updatePredictiveContext({
              recentActivity: [{
                type: "external_trigger",
                timestamp: Date.now(),
                data: { category, context },
              }],
            });
          }

          // Run immediate prediction check
          const predictions = await checkPredictions();

          return jsonResult({
            success: true,
            predictions,
            triggered: true,
          });
        }

        default:
          return jsonResult({
            success: false,
            error: `Unknown action: ${action}`,
          });
      }
    },
  };
}
