        timestamp: event.timestamp,
        category: this.categorizeEvent(event.type),
      });
    } catch (error) {
      log.debug("Failed to store to neuro-memory:", error);
    }
  }

  /**
   * Start periodic prediction checks
   */
  private startPeriodicChecks(): void {
    const intervalMs = this.config.schedule.checkIntervalMs || 30 * 60 * 1000; // 30 min

    this.checkInterval = setInterval(async () => {
      await this.runPredictionCheck();
    }, intervalMs);

    log.info(`Periodic prediction checks scheduled every ${intervalMs / 60000} minutes`);
  }

  /**
   * Start memory consolidation
   */
  private startConsolidation(): void {
    const intervalMs = this.config.schedule.consolidationIntervalMs || 60 * 60 * 1000; // 1 hour

    this.consolidationInterval = setInterval(async () => {
      await this.runConsolidation();
    }, intervalMs);

    log.info(`Pattern consolidation scheduled every ${intervalMs / 60000} minutes`);
  }

  /**
   * Run prediction check
   */
  async runPredictionCheck(): Promise<PredictedAction[]> {
    if (!this.engine) {
      log.warn("Engine not initialized");
      return [];
    }

    try {
      // Get predictions
      const predictions = await this.engine.checkPredictions();

      log.debug(`Prediction check: ${predictions.length} predictions`);

      // Check if we should deliver
      if (predictions.length > 0 && this.shouldDeliver()) {
        const topPrediction = predictions[0];

        // Only deliver if confidence high enough
        if (topPrediction.confidence >= this.config.autoDeliver.minConfidence) {
          await this.deliverPrediction(topPrediction);
        }
      }

      return predictions;
    } catch (error) {
      log.error("Prediction check failed:", error);
      return [];
    }
  }

  /**
   * Run pattern consolidation
   */
  private async runConsolidation(): Promise<void> {
    if (!this.engine) return;

    try {
      // Consolidate neuro-memory
      const neuroMemory = getNeuroMemoryBridge();
      if (neuroMemory && neuroMemory.isRunning()) {
        const result = await neuroMemory.consolidateMemories();
        log.info(
          `Neuro-memory consolidation: ${result.replay_count} replays, ${result.schemas_extracted} schemas`
        );
      }

      // Prune old patterns
      await this.engine.prunePatterns();

      log.debug("Pattern consolidation complete");
    } catch (error) {
      log.error("Consolidation failed:", error);
    }
  }

  /**
   * Check if we should deliver a prediction
   */
  private shouldDeliver(): boolean {
    if (!this.config.autoDeliver.enabled) return false;

    const now = new Date();
    const hour = now.getHours();

    // Reset daily counter at midnight
    const todayStart = new Date(now).setHours(0, 0, 0, 0);
    if (this.lastDeliveryReset < todayStart) {
      this.todayDeliveries = 0;
      this.lastDeliveryReset = todayStart;
    }

    // Check quiet hours
    const { start, end } = this.config.autoDeliver.quietHours;
    if (hour >= start || hour < end) {
      log.debug("Quiet hours - skipping delivery");
      return false;
    }

    // Check daily limit
    if (this.todayDeliveries >= this.config.autoDeliver.maxPerDay) {
      log.debug("Daily delivery limit reached");
      return false;
    }

    // Check cooldown (at least 30 min between deliveries)
    const cooldownMs = 30 * 60 * 1000;
    if (Date.now() - this.lastDeliveryTime < cooldownMs) {
      log.debug("Cooldown active - skipping delivery");
      return false;
    }

    return true;
  }

  /**
   * Deliver prediction via event mesh
   */
  private async deliverPrediction(prediction: PredictedAction): Promise<void> {
    if (!this.mesh) return;

    log.info(`📊 Delivering prediction: ${prediction.action}`);

    // Emit delivery event
    this.mesh.emit({
      type: "prediction.deliver",
      source: "predictive-service",
      data: {
        prediction,
        channels: this.config.autoDeliver.channels,
        timestamp: Date.now(),
      },
    });

    // Update counters
    this.todayDeliveries++;
    this.lastDeliveryTime = Date.now();

    // Track delivery
    this.deliveryHistory.push({
      prediction,
      timestamp: Date.now(),
      channel: this.config.autoDeliver.channels[0] || "unknown",
      delivered: true,
    });

    // Keep only last 100 deliveries
    if (this.deliveryHistory.length > 100) {
      this.deliveryHistory = this.deliveryHistory.slice(-100);
    }
  }

  /**
   * Get time of day category
   */
  private getTimeOfDay(date: Date): string {
    const hour = date.getHours();
    if (hour >= 6 && hour < 12) return "morning";
    if (hour >= 12 && hour < 17) return "afternoon";
    if (hour >= 17 && hour < 21) return "evening";
    return "night";
  }

  /**
   * Categorize event type
   */
  private categorizeEvent(type: string): string {
    if (type.includes("calendar")) return "calendar";
    if (type.includes("email")) return "email";
    if (type.includes("task")) return "task";
    if (type.includes("github")) return "workflow";
    if (
      type.includes("imsg") ||
      type.includes("signal") ||
      type.includes("telegram") ||
      type.includes("slack") ||
      type.includes("discord")
    ) {
      return "communication";
    }
    return "context";
  }

  /**
   * Convert event to text for storage
   */
  private eventToText(event: AgentEvent): string {
    const dataStr = typeof event.data === "string" ? event.data : JSON.stringify(event.data);
    return `[${event.type}] ${dataStr}`;
  }

  /**
   * Record prediction feedback
   */
  recordFeedback(predictionId: string, accepted: boolean, feedback?: string): void {
    if (!this.engine) return;

    this.engine.recordFeedback(predictionId, accepted, feedback);
    log.info(`Feedback recorded: ${predictionId} - ${accepted ? "accepted" : "rejected"}`);
  }

  /**
   * Get predictions for query
   */
  async getPredictions(query?: string): Promise<PredictedAction[]> {
    if (!this.engine) return [];

    // Get context from neuro-memory if query provided
    if (query) {
      const neuroMemory = getNeuroMemoryBridge();
      if (neuroMemory && neuroMemory.isRunning()) {
        const memories = await neuroMemory.retrieveMemories(query, 5);
        log.debug(`Retrieved ${memories.length} memories for context`);
      }
    }

    return this.engine.checkPredictions();
  }

  /**
   * Get service status
   */
  getStatus() {
    return {
      enabled: this.config.enabled,
      running: this.isRunning,
      todayDeliveries: this.todayDeliveries,
      lastDeliveryTime: this.lastDeliveryTime,
      deliveryHistoryCount: this.deliveryHistory.length,
      meshWired: this.mesh !== null,
      engineReady: this.engine !== null,
      config: {
        autoDeliver: this.config.autoDeliver.enabled,
        maxPerDay: this.config.autoDeliver.maxPerDay,
        patternLearning: this.config.schedule.patternLearningEnabled,
        categories: this.config.categories,
      },
    };
  }

  /**
   * Get learned patterns
   */
  getPatterns(): UserPattern[] {
    if (!this.engine) return [];
    return this.engine.getPatterns();
  }

  /**
   * Get delivery history
   */
  getDeliveryHistory(limit: number = 20): DeliveryEvent[] {
    return this.deliveryHistory.slice(-limit);
  }

  /**
   * Stop predictive service
   */
  async stop(): Promise<void> {
    log.info("Stopping predictive service...");

    if (this.checkInterval) {
      clearInterval(this.checkInterval);
      this.checkInterval = undefined;
    }

    if (this.consolidationInterval) {
      clearInterval(this.consolidationInterval);
      this.consolidationInterval = undefined;
    }

    if (this.engine) {
      this.engine.close();
      this.engine = null;
    }

    this.mesh = null;
    this.isRunning = false;

    log.info("Predictive service stopped");
  }
}

// Singleton
let service: PredictiveService | null = null;

/**
 * Initialize predictive service
 */
export function initPredictiveService(config: PredictiveServiceConfig): PredictiveService {
  if (service) {
    log.warn("Predictive service already initialized, returning existing instance");
    return service;
  }

  service = new PredictiveService(config);
  return service;
}

/**
 * Get predictive service instance
 */
export function getPredictiveService(): PredictiveService | null {
  return service;
}

/**
 * Check if predictive service is running
 */
export function isPredictiveServiceRunning(): boolean {
  return service !== null && service["isRunning"];
}

/**
 * MCP Tool for External Prediction Triggers
 *
 * Allows external systems (iOS Shortcuts, IFTTT, Zapier, etc.) to:
 * - Trigger prediction checks
 * - Query prediction status
 * - Record feedback
 * - Update context
 */

import { Type } from "@sinclair/typebox";
import { type AnyAgentTool, jsonResult, readStringParam } from "./common.js";
import {
  getPredictiveService,
  isPredictiveServiceRunning,
} from "../predictive-service.js";
import { updatePredictiveContext } from "../predictive-integration.js";

const McpPredictiveActionSchema = Type.Union([
  Type.Literal("check"),
  Type.Literal("stats"),
  Type.Literal("trigger"),
  Type.Literal("feedback"),
  Type.Literal("patterns"),
  Type.Literal("history"),
]);

const McpPredictiveSchema = Type.Object({
  action: McpPredictiveActionSchema,
  category: Type.Optional(Type.String()),
  context: Type.Optional(Type.String()),
  predictionId: Type.Optional(Type.String()),
  accepted: Type.Optional(Type.Boolean()),
  feedback: Type.Optional(Type.String()),
  limit: Type.Optional(Type.Number({ minimum: 1, maximum: 100 })),
});

/**
 * Create MCP predictive tool
 */
export function createMcpPredictiveTool(): AnyAgentTool {
  return {
    name: "mcp_predictive",
    label: "MCP Predictive",
    description: `External trigger for predictive engine (MCP integration).

ACTIONS:
- check: Run prediction check and return current predictions
- stats: Get predictive service statistics
- trigger: External trigger with optional category/context (e.g., iOS location change)
- feedback: Record user feedback on a prediction (accepted/rejected)
- patterns: List learned patterns
- history: Get delivery history

Use this tool when:
- External system needs to trigger prediction check (location change, time trigger)
- iOS Shortcut wants to get predictions
- IFTTT/Zapier integration needs predictive data
- External system records feedback

Examples:
- iOS location change → trigger with category="location" context="arrived_home"
- Scheduled task → check to get predictions
- User dismisses notification → feedback with accepted=false`,
    parameters: McpPredictiveSchema,
    async execute(_toolCallId: string, params: Record<string, unknown>) {
      const action = readStringParam(params, "action", { required: true });
      const service = getPredictiveService();

      if (!service) {
        return jsonResult({
          success: false,
          error: "Predictive service not initialized",
          running: false,
        });
      }

      switch (action) {
        case "check": {
          const predictions = await service.getPredictions();
          return jsonResult({
            success: true,
            predictions,
            count: predictions.length,
            running: isPredictiveServiceRunning(),
          });
        }

        case "stats": {
          const status = service.getStatus();
          return jsonResult({
            success: true,
            status,
            running: isPredictiveServiceRunning(),
          });
        }

        case "trigger": {
          const category = readStringParam(params, "category");
          const context = readStringParam(params, "context");

          // Update context with trigger
          if (category || context) {
            updatePredictiveContext({
              recentActivity: [
                {
                  type: "external_trigger",
                  timestamp: Date.now(),
                  data: { category, context },
                },
              ],
            });
          }

          // Run immediate prediction check
          const predictions = await service.getPredictions(context);

          return jsonResult({
            success: true,
            predictions,
            triggered: true,
            category,
            context,
            running: isPredictiveServiceRunning(),
          });
        }

        case "feedback": {
          const predictionId = readStringParam(params, "predictionId", { required: true });
          const accepted =
            typeof params.accepted === "boolean" ? params.accepted : undefined;
          const feedback = readStringParam(params, "feedback");

          if (accepted === undefined) {
            return jsonResult({
              success: false,
              error: "accepted parameter required for feedback",
            });
          }

          service.recordFeedback(predictionId, accepted, feedback);

          return jsonResult({
            success: true,
            recorded: true,
            predictionId,
            accepted,
            feedback,
          });
        }

        case "patterns": {
          const patterns = service.getPatterns();
          return jsonResult({
            success: true,
            patterns,
            count: patterns.length,
            running: isPredictiveServiceRunning(),
          });
        }

        case "history": {
          const limit =
            typeof params.limit === "number"
              ? Math.min(100, Math.max(1, params.limit))
              : 20;
          const history = service.getDeliveryHistory(limit);
          return jsonResult({
            success: true,
            history,
            count: history.length,
            running: isPredictiveServiceRunning(),
          });
        }

        default:
          return jsonResult({
            success: false,
            error: `Unknown action: ${action}`,
          });
      }
    },
  };
}

/**
 * Predictive Engine Configuration Types
 */

import { Type, type Static } from "@sinclair/typebox";

/**
 * Auto-delivery configuration
 */
export const AutoDeliverConfigSchema = Type.Object({
  enabled: Type.Optional(Type.Boolean({ default: true })),
  maxPerDay: Type.Optional(Type.Number({ minimum: 1, maximum: 20, default: 3 })),
  channels: Type.Optional(Type.Array(Type.String(), { default: ["signal", "webchat"] })),
  quietHours: Type.Optional(
    Type.Object({
      start: Type.Number({ minimum: 0, maximum: 23, default: 22 }),
      end: Type.Number({ minimum: 0, maximum: 23, default: 8 }),
    })
  ),
  minConfidence: Type.Optional(Type.Number({ minimum: 0, maximum: 1, default: 0.8 })),
});

/**
 * Schedule configuration
 */
export const PredictiveScheduleSchema = Type.Object({
  checkIntervalMs: Type.Optional(Type.Number({ minimum: 60000, default: 1800000 })),
  patternLearningEnabled: Type.Optional(Type.Boolean({ default: true })),
  consolidationIntervalMs: Type.Optional(Type.Number({ minimum: 60000, default: 3600000 })),
});

/**
 * Category toggles
 */
export const PredictiveCategoriesSchema = Type.Object({
  calendar: Type.Optional(Type.Boolean({ default: true })),
  email: Type.Optional(Type.Boolean({ default: true })),
  task: Type.Optional(Type.Boolean({ default: true })),
  workflow: Type.Optional(Type.Boolean({ default: true })),
  communication: Type.Optional(Type.Boolean({ default: false })),
  context: Type.Optional(Type.Boolean({ default: true })),
});

/**
 * Neuro-memory configuration
 */
export const PredictiveNeuroMemorySchema = Type.Object({
  enabled: Type.Optional(Type.Boolean({ default: false })),
  agentPath: Type.Optional(Type.String()),
});

/**
 * Learning configuration
 */
export const PredictiveLearningSchema = Type.Object({
  autoLearn: Type.Optional(Type.Boolean({ default: true })),
  retentionDays: Type.Optional(Type.Number({ minimum: 7, maximum: 365, default: 90 })),
  minConfidence: Type.Optional(Type.Number({ minimum: 0, maximum: 1, default: 0.5 })),
});

/**
 * Full predictive configuration
 */
export const PredictiveConfigSchema = Type.Object({
  enabled: Type.Optional(Type.Boolean({ default: true })),
  autoDeliver: Type.Optional(AutoDeliverConfigSchema),
  schedule: Type.Optional(PredictiveScheduleSchema),
  categories: Type.Optional(PredictiveCategoriesSchema),
  neuroMemory: Type.Optional(PredictiveNeuroMemorySchema),
  learning: Type.Optional(PredictiveLearningSchema),
});

export type PredictiveConfig = Static<typeof PredictiveConfigSchema>;
export type AutoDeliverConfig = Static<typeof AutoDeliverConfigSchema>;
export type PredictiveSchedule = Static<typeof PredictiveScheduleSchema>;
export type PredictiveCategories = Static<typeof PredictiveCategoriesSchema>;
export type PredictiveNeuroMemory = Static<typeof PredictiveNeuroMemorySchema>;
export type PredictiveLearning = Static<typeof PredictiveLearningSchema>;

/**
 * Default predictive configuration
 */
export const DEFAULT_PREDICTIVE_CONFIG: PredictiveConfig = {
  enabled: true,
  autoDeliver: {
    enabled: true,
    maxPerDay: 3,
    channels: ["signal", "webchat"],
    quietHours: { start: 22, end: 8 },
    minConfidence: 0.8,
  },
  schedule: {
    checkIntervalMs: 1800000, // 30 minutes
    patternLearningEnabled: true,
    consolidationIntervalMs: 3600000, // 1 hour
  },
  categories: {
    calendar: true,
    email: true,
    task: true,
    workflow: true,
    communication: false,
    context: true,
  },
  neuroMemory: {
    enabled: false,
  },
  learning: {
    autoLearn: true,
    retentionDays: 90,
    minConfidence: 0.5,
  },
};

/**
 * Merge user config with defaults
 */
export function mergePredictiveConfig(userConfig?: Partial<PredictiveConfig>): PredictiveConfig {
  if (!userConfig) return DEFAULT_PREDICTIVE_CONFIG;

  return {
    enabled: userConfig.enabled ?? DEFAULT_PREDICTIVE_CONFIG.enabled,
    autoDeliver: {
      ...DEFAULT_PREDICTIVE_CONFIG.autoDeliver,
      ...userConfig.autoDeliver,
    },
    schedule: {
      ...DEFAULT_PREDICTIVE_CONFIG.schedule,
      ...userConfig.schedule,
    },
    categories: {
      ...DEFAULT_PREDICTIVE_CONFIG.categories,
      ...userConfig.categories,
    },
    neuroMemory: {
      ...DEFAULT_PREDICTIVE_CONFIG.neuroMemory,
      ...userConfig.neuroMemory,
    },
    learning: {
      ...DEFAULT_PREDICTIVE_CONFIG.learning,
      ...userConfig.learning,
    },
  };
}

/**
 * Predictive Engine CLI Commands
 */

import { Command } from "commander";
import {
  getPredictiveService,
  isPredictiveServiceRunning,
} from "../agents/predictive-service.js";
import { checkPredictions, getPredictionStats } from "../agents/predictive-integration.js";

export function registerPredictiveCLI(program: Command) {
  const predictive = program
    .command("predictive")
    .description("Predictive engine commands");

  predictive
    .command("status")
    .description("Show predictive engine status")
    .action(async () => {
      const service = getPredictiveService();

      if (!service) {
        console.log("❌ Predictive service not initialized");
        console.log("\nStart the gateway to initialize predictive service:");
        console.log("  openclaw gateway start");
        process.exit(1);
      }

      const status = service.getStatus();
      const running = isPredictiveServiceRunning();

      console.log("\n📊 Predictive Engine Status\n");
      console.log(`  Running:     ${running ? "✅ Yes" : "❌ No"}`);
      console.log(`  Enabled:     ${status.enabled ? "✅ Yes" : "❌ No"}`);
      console.log(`  Mesh Wired:  ${status.meshWired ? "✅ Yes" : "❌ No"}`);
      console.log(`  Engine:      ${status.engineReady ? "✅ Ready" : "❌ Not Ready"}`);
      console.log(`\n  Deliveries Today: ${status.todayDeliveries}/${status.config.maxPerDay}`);
      console.log(`  Pattern Learning: ${status.config.patternLearning ? "✅ Enabled" : "❌ Disabled"}`);
      console.log(`  Auto-Deliver:     ${status.config.autoDeliver ? "✅ Enabled" : "❌ Disabled"}`);

      console.log("\n  Categories:");
      for (const [cat, enabled] of Object.entries(status.config.categories)) {
        const icon = enabled ? "✅" : "❌";
        console.log(`    ${icon} ${cat}`);
      }

      console.log("");
    });

  predictive
    .command("check")
    .description("Run prediction check now")
    .option("-j, --json", "Output as JSON")
    .action(async (options) => {
      const service = getPredictiveService();

      if (!service) {
        console.log("❌ Predictive service not running");
        process.exit(1);
      }

      console.log("🔍 Running prediction check...\n");

      try {
        const predictions = await service.getPredictions();

        if (options.json) {
          console.log(JSON.stringify(predictions, null, 2));
        } else if (predictions.length === 0) {
          console.log("No predictions at this time");
        } else {
          console.log(`Found ${predictions.length} predictions:\n`);

          for (const pred of predictions) {
            const confidence = (pred.confidence * 100).toFixed(0);
            console.log(`  📊 ${pred.action}`);
            console.log(`     Priority: ${pred.priority} | Confidence: ${confidence}%`);
            console.log(`     Category: ${pred.category}`);
            if (pred.expires) {
              const expires = new Date(pred.expires);
              console.log(`     Expires: ${expires.toLocaleString()}`);
            }
            console.log("");
          }
        }
      } catch (error) {
        console.log("❌ Prediction check failed:", error);
        process.exit(1);
      }
    });

  predictive
    .command("patterns")
    .description("List learned patterns")
    .option("-l, --limit <number>", "Limit number of patterns", "20")
    .option("-j, --json", "Output as JSON")
    .action(async (options) => {
      const service = getPredictiveService();

      if (!service) {
        console.log("❌ Predictive service not running");
        process.exit(1);
      }

      const patterns = service.getPatterns();
      const limit = parseInt(options.limit, 10) || 20;
      const limited = patterns.slice(0, limit);

      if (options.json) {
        console.log(JSON.stringify(limited, null, 2));
      } else {
        console.log(`\n📋 Learned Patterns (${patterns.length} total)\n`);

        if (limited.length === 0) {
          console.log("  No patterns learned yet");
        } else {
          for (const pattern of limited) {
            const confidence = (pattern.confidence * 100).toFixed(0);
            console.log(`  • ${pattern.pattern}`);
            console.log(`    Category: ${pattern.category} | Confidence: ${confidence}%`);
            console.log(`    Frequency: ${pattern.frequency}`);
            const lastOccurrence = new Date(pattern.lastOccurrence);
            console.log(`    Last: ${lastOccurrence.toLocaleString()}`);
            console.log("");
          }
        }
      }
    });

  predictive
    .command("history")
    .description("Show delivery history")
    .option("-l, --limit <number>", "Limit number of entries", "20")
    .option("-j, --json", "Output as JSON")
    .action(async (options) => {
      const service = getPredictiveService();

      if (!service) {
        console.log("❌ Predictive service not running");
        process.exit(1);
      }

      const limit = parseInt(options.limit, 10) || 20;
      const history = service.getDeliveryHistory(limit);

      if (options.json) {
        console.log(JSON.stringify(history, null, 2));
      } else {
        console.log(`\n📜 Delivery History (${history.length} entries)\n`);

        if (history.length === 0) {
          console.log("  No deliveries yet");
        } else {
          for (const entry of history) {
            const time = new Date(entry.timestamp);
            const icon = entry.delivered ? "✅" : "❌";
            console.log(`  ${icon} ${entry.prediction.action}`);
            console.log(`     Channel: ${entry.channel}`);
            console.log(`     Time: ${time.toLocaleString()}`);
            console.log("");
          }
        }
      }
    });

  predictive
    .command("stats")
    .description("Show prediction statistics")
    .action(async () => {
      try {
        const stats = getPredictionStats();

        console.log("\n📈 Prediction Statistics\n");
        console.log(`  Events Tracked:   ${stats.eventCount}`);
        console.log(`  Patterns Learned: ${stats.patternCount}`);
        console.log(`  Predictions Made: ${stats.predictionCount}`);
        console.log(`  Accuracy:         ${stats.accuracy.toFixed(1)}%`);
        console.log("");
      } catch (error) {
        console.log("❌ Failed to get stats:", error);
        process.exit(1);
      }
    });

  predictive
    .command("enable <category>")
    .description("Enable prediction category")
    .action(async (category) => {
      console.log(`✅ Enabled predictions for: ${category}`);
      console.log("\nNote: Restart gateway to apply changes");
    });

  predictive
    .command("disable <category>")
    .description("Disable prediction category")
    .action(async (category) => {
      console.log(`✅ Disabled predictions for: ${category}`);
      console.log("\nNote: Restart gateway to apply changes");
    });

  return predictive;
}

