/**
 * Learn a new pattern from user behavior
 */
learnPattern(pattern: Omit<UserPattern, "id">): void {
  const id = crypto.randomUUID();
  const userPattern: UserPattern = {
    id,
    ...pattern,
  };

  this.patterns.set(id, userPattern);
  this.context.patterns = Array.from(this.patterns.values());

  if (this.enablePersistence && this.db) {
    this.savePattern(userPattern);
  }

  log.info(`Learned new pattern: ${pattern.pattern} (${pattern.category})`);

  // Store in neuro-memory for semantic retrieval
  this.storePatternToNeuroMemory(userPattern).catch((err) => {
    log.debug("Failed to store pattern to neuro-memory:", err);
  });
}

/**
 * Store pattern to neuro-memory-agent
 */
private async storePatternToNeuroMemory(pattern: UserPattern): Promise<void> {
  const neuroMemory = getNeuroMemoryBridge();
  if (!neuroMemory || !neuroMemory.isRunning()) return;

  try {
    const content = `User pattern: ${pattern.pattern} in category ${pattern.category}`;
    const result = await neuroMemory.storeMemory(content, {
      pattern: pattern.pattern,
      category: pattern.category,
      frequency: pattern.frequency,
      confidence: pattern.confidence,
      lastOccurrence: pattern.lastOccurrence,
    });

    if (result.is_novel) {
      log.info(
        `🧠 Novel pattern detected: ${pattern.pattern} (surprise: ${result.surprise.toFixed(3)})`
      );
    }
  } catch (error) {
    log.debug("Neuro-memory store failed:", error);
  }
}

/**
 * Get context from neuro-memory
 */
async getContextFromNeuroMemory(query: string): Promise<Episode[]> {
  const neuroMemory = getNeuroMemoryBridge();
  if (!neuroMemory || !neuroMemory.isRunning()) {
    return [];
  }

  try {
    const episodes = await neuroMemory.retrieveMemories(query, 5);
    log.debug(`Retrieved ${episodes.length} episodes from neuro-memory`);
    return episodes;
  } catch (error) {
    log.debug("Neuro-memory retrieval failed:", error);
    return [];
  }
}

