  /**
   * Prune old patterns based on age and confidence
   */
  async prunePatterns(): Promise<number> {
    const cutoff = Date.now() - 90 * 24 * 60 * 60 * 1000; // 90 days
    let pruned = 0;

    // Prune from memory
    for (const [id, pattern] of this.patterns.entries()) {
      if (pattern.lastOccurrence < cutoff || pattern.confidence < this.minConfidence) {
        this.patterns.delete(id);
        pruned++;
      }
    }

    this.context.patterns = Array.from(this.patterns.values());

    // Prune from database
    if (this.db && this.enablePersistence) {
      try {
        const result = this.db
          .prepare(
            "DELETE FROM prediction_patterns WHERE last_occurrence < ? OR confidence < ?"
          )
          .run(cutoff, this.minConfidence);

        pruned += Number(result.changes);
      } catch (error) {
        log.error("Failed to prune patterns from database:", error);
      }
    }

    log.info(`Pruned ${pruned} old patterns`);
    return pruned;
  }

  /**
   * Get all learned patterns
   */
  getPatterns(): UserPattern[] {
    return Array.from(this.patterns.values());
  }

  /**
   * Close the engine
   */
  close(): void {
    this.rules.clear();
    this.patterns.clear();
    this.recentPredictions = [];
    log.info(`Predictive engine closed for agent: ${this.agentId}`);
  }
}

