        confidence: 0.9,
        message: "Same prediction",
        data: { key: "value" },
      }),
      enabled: true,
      priority: 1,
    });

    await service.start();

    // Check multiple times
    await service.checkAndDeliver();
    await service.checkAndDeliver();
    await service.checkAndDeliver();

    // Should only deliver once
    expect(deliveredPredictions.length).toBe(1);
  });
});

/**
 * Predictive Engine Dashboard Endpoint
 * Serves prediction data for Web UI
 */

import type { Request, Response } from "express";
import {
  checkPredictions,
  getPredictionStats,
  getRecentDeliveries,
} from "../../agents/predictive-integration.js";
import {
  isPredictiveServiceRunning,
  getPredictiveService,
} from "../../agents/predictive-service.js";

/**
 * GET /api/predictive/dashboard
 * Returns dashboard data for predictive engine
 */
export async function handlePredictiveDashboard(
  req: Request,
  res: Response,
): Promise<void> {
  try {
    const running = isPredictiveServiceRunning();

    if (!running) {
      res.json({
        status: "disabled",
        message: "Predictive engine not running",
        data: null,
      });
      return;
    }

    const service = getPredictiveService();
    if (!service) {
      res.status(500).json({ error: "Service not available" });
      return;
    }

    const stats = getPredictionStats();
    const predictions = await checkPredictions();
    const deliveries = getRecentDeliveries(20);
    const config = service.getConfig();
    const patterns = service.getEngine().getPatterns().slice(0, 50);

    res.json({
      status: "running",
      config: {
        autoDeliver: config.autoDeliver.enabled,
        maxPerDay: config.autoDeliver.maxPerDay,
        quietHours: config.autoDeliver.quietHours,
        minConfidence: config.autoDeliver.minConfidence,
      },
      stats: {
        totalEvents: stats.totalEvents,
        patternCount: stats.patternCount,
        todayPredictions: stats.todayPredictions,
        todayDeliveries: stats.todayDeliveries,
        accuracy: stats.accuracy,
      },
      predictions: predictions.slice(0, 10).map(p => ({
        action: p.action,
        category: p.category,
        priority: p.priority,
        confidence: Math.round(p.confidence * 100),
        message: p.message,
        timestamp: p.timestamp,
      })),
      recentDeliveries: deliveries.map(d => ({
        action: d.action,
        message: d.message,
        timestamp: d.timestamp,
        accepted: d.accepted,
      })),
      topPatterns: patterns
        .sort((a, b) => b.confidence - a.confidence)
        .slice(0, 20)
        .map(p => ({
          name: p.name,
          type: p.type,
          confidence: Math.round(p.confidence * 100),
          occurrences: p.occurrences,
          lastSeen: p.lastSeen,
        })),
    });
  } catch (error) {
    console.error("Dashboard error:", error);
    res.status(500).json({
      error: "Failed to fetch dashboard data",
      message: error instanceof Error ? error.message : String(error),
    });
  }
}

/**
 * POST /api/predictive/feedback
 * Record user feedback on prediction
 */
export async function handlePredictiveFeedback(
  req: Request,
  res: Response,
): Promise<void> {
  try {
    const { predictionId, accepted, feedback } = req.body;

    if (!predictionId) {
      res.status(400).json({ error: "predictionId required" });
      return;
    }

    const service = getPredictiveService();
    if (!service) {
      res.status(500).json({ error: "Service not available" });
      return;
    }

    service.recordFeedback(predictionId, accepted, feedback);

    res.json({
      success: true,
      message: "Feedback recorded",
    });
  } catch (error) {
    console.error("Feedback error:", error);
    res.status(500).json({
      error: "Failed to record feedback",
      message: error instanceof Error ? error.message : String(error),
    });
  }
}

/**
 * GET /api/predictive/patterns
 * Get learned patterns
 */
export async function handleGetPatterns(
  req: Request,
  res: Response,
): Promise<void> {
  try {
    const limit = parseInt(req.query.limit as string || "50", 10);
    const type = req.query.type as string;

    const service = getPredictiveService();
    if (!service) {
      res.status(500).json({ error: "Service not available" });
      return;
    }

    let patterns = service.getEngine().getPatterns();

    if (type) {
      patterns = patterns.filter(p => p.type === type);
    }

    res.json({
      patterns: patterns
        .slice(0, limit)
        .map(p => ({
          id: p.id,
          name: p.name,
          type: p.type,
          confidence: Math.round(p.confidence * 100),
          occurrences: p.occurrences,
          lastSeen: p.lastSeen,
          metadata: p.metadata,
        })),
      total: patterns.length,
    });
  } catch (error) {
    console.error("Patterns error:", error);
    res.status(500).json({
      error: "Failed to fetch patterns",
      message: error instanceof Error ? error.message : String(error),
    });
  }
}

/**
 * Performance tests for predictive engine with large event history
 */

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { PredictiveEngine } from "./predictive-engine.js";
import { PredictiveService, type PredictiveServiceConfig } from "./predictive-service.js";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { mkdirSync, rmSync } from "node:fs";

describe("Performance - Large Event History", () => {
  let engine: PredictiveEngine;
  let tempDir: string;

  beforeEach(() => {
    tempDir = join(tmpdir(), `predictive-perf-test-${Date.now()}`);
    mkdirSync(tempDir, { recursive: true });

    engine = new PredictiveEngine({
      dbPath: join(tempDir, "perf-test.db"),
      enablePersistence: true,
      enableNeuroMemory: false,
    });
  });

  afterEach(() => {
    rmSync(tempDir, { recursive: true, force: true });
  });

  it("should handle 10,000 events efficiently", () => {
    const startTime = Date.now();

    // Record 10,000 events
    for (let i = 0; i < 10000; i++) {
      engine.recordEvent({
        type: "tool_execution",
        tool: ["weather", "calendar", "email", "task", "telegram"][i % 5],
        timestamp: Date.now() - i * 1000,
        data: { index: i },
      });
    }

    const recordTime = Date.now() - startTime;
    console.log(`Recording 10,000 events: ${recordTime}ms`);

    // Should complete in under 5 seconds
    expect(recordTime).toBeLessThan(5000);

    // Pattern detection should still be fast
    const patterns = engine.getPatterns();
    const patternTime = Date.now() - startTime - recordTime;
    console.log(`Pattern detection: ${patternTime}ms`);

    expect(patterns.length).toBeGreaterThan(0);
    expect(patternTime).toBeLessThan(1000);
  });

  it("should generate predictions quickly with large pattern set", async () => {
    // Create 100 custom rules
    for (let i = 0; i < 100; i++) {
      engine.addRule({
        id: `perf-rule-${i}`,
        name: `Performance Rule ${i}`,
        condition: () => Math.random() > 0.5,
        action: () => ({
          action: `action_${i}`,
          category: "task",
          priority: "medium",
          confidence: 0.7 + Math.random() * 0.3,
          message: `Test prediction ${i}`,
          data: {},
        }),
        enabled: true,
        priority: i,
      });
    }

    // Record 1,000 events
    for (let i = 0; i < 1000; i++) {
      engine.recordEvent({
        type: "tool_execution",
        tool: "test",
        timestamp: Date.now() - i * 1000,
      });
    }

    const startTime = Date.now();
    const predictions = await engine.predict({ timestamp: Date.now() });
    const predictTime = Date.now() - startTime;

    console.log(`Prediction generation with 100 rules: ${predictTime}ms`);

    expect(predictTime).toBeLessThan(500);
    expect(predictions.length).toBeGreaterThan(0);
  });

  it("should prune old patterns efficiently", () => {
    // Create 500 patterns
    for (let i = 0; i < 500; i++) {
      engine.recordEvent({
        type: "tool_execution",
        tool: `tool_${i % 50}`,
        timestamp: Date.now() - i * 86400000, // Spread over 500 days
        data: { pattern: i },
      });
    }

    const beforePrune = engine.getPatterns().length;

    const startTime = Date.now();
    engine.prunePatterns();
    const pruneTime = Date.now() - startTime;

    const afterPrune = engine.getPatterns().length;

    console.log(`Pruning ${beforePrune} patterns: ${pruneTime}ms`);
    console.log(`Before: ${beforePrune}, After: ${afterPrune}`);

    expect(pruneTime).toBeLessThan(1000);
    expect(afterPrune).toBeLessThan(beforePrune);
  });

  it("should maintain performance with concurrent event recording", async () => {
    const eventsPerBatch = 1000;
    const batches = 5;

    const startTime = Date.now();

    // Simulate concurrent recording
    const promises = Array.from({ length: batches }, (_, batchIndex) => {
      return new Promise<void>((resolve) => {
        for (let i = 0; i < eventsPerBatch; i++) {
          engine.recordEvent({
            type: "tool_execution",
            tool: "concurrent_test",
            timestamp: Date.now() - (batchIndex * eventsPerBatch + i) * 1000,
            data: { batch: batchIndex },
          });
        }
        resolve();
      });
    });

    await Promise.all(promises);

    const recordTime = Date.now() - startTime;
    console.log(`Concurrent recording of ${eventsPerBatch * batches} events: ${recordTime}ms`);

    expect(recordTime).toBeLessThan(3000);
  });

  it("should handle database queries efficiently", () => {
    // Populate with 5,000 events
    for (let i = 0; i < 5000; i++) {
      engine.recordEvent({
        type: "tool_execution",
        tool: ["weather", "calendar", "email"][i % 3],
        timestamp: Date.now() - i * 1000,
        data: { index: i },
      });
    }

    const statsStart = Date.now();
    const stats = engine.getStats();
    const statsTime = Date.now() - statsStart;

    console.log(`Stats query: ${statsTime}ms`);
    expect(statsTime).toBeLessThan(100);

    const patternsStart = Date.now();
    const patterns = engine.getPatterns();
    const patternsTime = Date.now() - patternsStart;

    console.log(`Patterns query: ${patternsTime}ms`);
    expect(patternsTime).toBeLessThan(100);
  });

  it("should handle memory pressure gracefully", () => {
    // Force garbage collection before test
    if (global.gc) {
      global.gc();
    }

    const memoryBefore = process.memoryUsage().heapUsed;

    // Process large batch
    for (let i = 0; i < 20000; i++) {
      engine.recordEvent({
        type: "tool_execution",
        tool: "memory_test",
        timestamp: Date.now() - i * 1000,
        data: {
          largePayload: "x".repeat(100), // 100 bytes per event
        },
      });
    }

    const memoryAfter = process.memoryUsage().heapUsed;
    const memoryIncrease = memoryAfter - memoryBefore;
    const memoryIncreaseMB = memoryIncrease / 1024 / 1024;

    console.log(`Memory increase: ${memoryIncreaseMB.toFixed(2)} MB`);

    // Should not use more than 50MB for 20k events
    expect(memoryIncreaseMB).toBeLessThan(50);
  });
});

describe("Service Performance", () => {
  let service: PredictiveService;
  let tempDir: string;

  beforeEach(async () => {
    tempDir = join(tmpdir(), `predictive-service-perf-${Date.now()}`);
    mkdirSync(tempDir, { recursive: true });

    const config: PredictiveServiceConfig = {
      enabled: true,
      agentId: "perf-test",
      db: null,
      neuroMemory: { enabled: false },
      autoDeliver: {
        enabled: true,
        maxPerDay: 3,
        channels: ["test"],
        quietHours: { start: 22, end: 8 },
        minConfidence: 0.8,
      },
      schedule: {
        checkIntervalMs: 60000,
        patternLearningEnabled: true,
        consolidationIntervalMs: 3600000,
      },
    };

    service = new PredictiveService(config);
  });

  afterEach(() => {
    service.stop();
    rmSync(tempDir, { recursive: true, force: true });
  });

  it("should start service quickly", async () => {
    const startTime = Date.now();
    await service.start();
    const start_time = Date.now() - startTime;

    console.log(`Service start: ${start_time}ms`);
    expect(start_time).toBeLessThan(1000);
  });

  it("should handle rapid check cycles", async () => {
    await service.start();

    // Add predictions
    const engine = service.getEngine();
    engine.addRule({
      id: "rapid-test",
      name: "Rapid Test",
      condition: () => true,
      action: () => ({
        action: "test",
        category: "task",
        priority: "high",
        confidence: 0.9,
        message: "Test",
        data: {},
      }),
      enabled: true,
      priority: 1,
    });

    const startTime = Date.now();

    // Run 10 check cycles
    for (let i = 0; i < 10; i++) {
      await service.checkAndDeliver();
    }

    const checkTime = Date.now() - startTime;
    console.log(`10 check cycles: ${checkTime}ms`);

    expect(checkTime).toBeLessThan(2000);
  });
});

