/**
 * Predictive engine gateway handlers
 */

import type { GatewayRequestHandlers } from "./types.js";
import {
  checkPredictions,
  getPredictionStats,
  getRecentDeliveries,
} from "../../agents/predictive-integration.js";
import {
  getPredictiveService,
  isPredictiveServiceRunning,
} from "../../agents/predictive-service.js";

export const predictiveHandlers: GatewayRequestHandlers = {
  /**
   * Get predictive engine status
   */
  "predictive.status": async (_params, _options) => {
    const running = isPredictiveServiceRunning();

    if (!running) {
      return {
        status: "disabled",
        message: "Predictive engine not running",
      };
    }

    const service = getPredictiveService();
    if (!service) {
      return {
        status: "error",
        message: "Service not available",
      };
    }

    const stats = getPredictionStats();
    const config = service.getConfig();

    return {
      status: "running",
      config: {
        autoDeliver: config.autoDeliver.enabled,
        maxPerDay: config.autoDeliver.maxPerDay,
        quietHours: config.autoDeliver.quietHours,
        minConfidence: config.autoDeliver.minConfidence,
      },
      stats,
    };
  },

  /**
   * Check current predictions
   */
  "predictive.check": async (_params, _options) => {
    const predictions = await checkPredictions();

    return {
      predictions: predictions.slice(0, 10),
      count: predictions.length,
    };
  },

  /**
   * Get learned patterns
   */
  "predictive.patterns": async (params, _options) => {
    const service = getPredictiveService();
    if (!service) {
      return { patterns: [], error: "Service not running" };
    }

    const limit = typeof params?.limit === "number" ? Math.min(100, params.limit) : 50;
    const type = params?.type as string | undefined;

    let patterns = service.getPatterns();

    if (type) {
      patterns = patterns.filter(p => p.type === type);
    }

    return {
      patterns: patterns.slice(0, limit).map(p => ({
        id: p.id,
        name: p.name,
        type: p.type,
        confidence: Math.round(p.confidence * 100),
        occurrences: p.occurrences,
        lastSeen: p.lastSeen,
      })),
      total: patterns.length,
    };
  },

  /**
   * Get prediction history
   */
  "predictive.history": async (params, _options) => {
    const limit = typeof params?.limit === "number" ? Math.min(100, params.limit) : 20;
    const deliveries = getRecentDeliveries(limit);

    return {
      deliveries,
      count: deliveries.length,
    };
  },

  /**
   * Get detailed statistics
   */
  "predictive.stats": async (_params, _options) => {
    const stats = getPredictionStats();
    return stats;
  },

  /**
   * Record feedback on a prediction
   */
  "predictive.feedback": async (params, _options) => {
    const service = getPredictiveService();
    if (!service) {
      return { success: false, error: "Service not running" };
    }

    const predictionId = params?.predictionId as string;
    const accepted = params?.accepted as boolean | undefined;
    const feedback = params?.feedback as string | undefined;

    if (!predictionId) {
      return { success: false, error: "predictionId required" };
    }

    service.recordFeedback(predictionId, accepted ?? true, feedback);

    return { success: true };
  },

  /**
   * Enable/disable auto-delivery
   */
  "predictive.setAutoDeliver": async (params, _options) => {
    const service = getPredictiveService();
    if (!service) {
      return { success: false, error: "Service not running" };
    }

    const enabled = params?.enabled as boolean;

    if (enabled) {
      service.enableAutoDelivery();
      return { success: true, autoDeliver: true };
    } else {
      service.disableAutoDelivery();
      return { success: true, autoDeliver: false };
    }
  },

  /**
   * Get dashboard data (comprehensive)
   */
  "predictive.dashboard": async (_params, _options) => {
    const running = isPredictiveServiceRunning();

    if (!running) {
      return {
        status: "disabled",
        message: "Predictive engine not running",
      };
    }

    const service = getPredictiveService();
    if (!service) {
      return { status: "error", message: "Service not available" };
    }

    const stats = getPredictionStats();
    const predictions = await checkPredictions();
    const deliveries = getRecentDeliveries(20);
    const config = service.getConfig();
    const patterns = service.getPatterns().slice(0, 50);

    return {
      status: "running",
      config: {
        autoDeliver: config.autoDeliver.enabled,
        maxPerDay: config.autoDeliver.maxPerDay,
        quietHours: config.autoDeliver.quietHours,
        minConfidence: config.autoDeliver.minConfidence,
      },
      stats: {
        totalEvents: stats.totalEvents,
        patternCount: stats.patternCount,
        todayPredictions: stats.todayPredictions,
        todayDeliveries: stats.todayDeliveries,
        accuracy: stats.accuracy,
      },
      predictions: predictions.slice(0, 10),
      recentDeliveries: deliveries,
      topPatterns: patterns
        .sort((a, b) => b.confidence - a.confidence)
        .slice(0, 20)
        .map(p => ({
          name: p.name,
          type: p.type,
          confidence: Math.round(p.confidence * 100),
          occurrences: p.occurrences,
          lastSeen: p.lastSeen,
        })),
    };
  },
};

